import javax.swing.SwingUtilities;

import com.asbestosstar.crashdetector.MonitorDePID;
import com.asbestosstar.crashdetector.gui.tipos.lectador.LectadorDeConsolasGUI.ErrorDeLectador;

/**
 * Visor rápido para logs grandes.
 *
 * Este componente reemplaza JList + NumeradorDeLineas.
 *
 * Ventajas: - No crea JLabel por cada fila. - No usa CellRenderer. - No
 * pregunta getCellBounds() miles de veces. - Dibuja solamente las líneas
 * visibles. - Los números de línea se dibujan en el mismo componente. - El
 * scroll usa matemática simple: y / alturaLinea.
 *
 * Está diseñado como API pública, sin encapsulación fuerte, para que otras
 * partes de CrashDetector puedan tocar el estado directamente si lo necesitan.
 */
public class VisorLogVirtual extends JComponent implements Scrollable {

	private static final long serialVersionUID = 1L;

	public FuenteDeLineas fuente;

	public int alturaLinea = 16;
	public int margenIzquierdo = 8;
	public int margenDerechoNumero = 8;
	public int anchoNumeros = 56;
	public int lineaSeleccionada = -1;

	public int lineaSeleccionInicio = -1;
	public int lineaSeleccionFin = -1;
	public boolean arrastrandoSeleccion = false;

	public Color colorFondo = Color.BLACK;
	public Color colorTexto = Color.WHITE;
	public Color colorError = new Color(255, 165, 0);
	public Color colorPila = Color.BLUE;
	public Color colorTextoSobreColor = Color.BLACK;
	public Color colorFondoNumeros = new Color(25, 25, 25);
	public Color colorTextoNumeros = Color.LIGHT_GRAY;
	public Color colorSeleccion = new Color(70, 70, 70);
	public Color colorAdvertencia = new Color(255, 220, 80);
	public boolean usarTextoAutomaticoSobreColores = true;

	public Map<Integer, ErrorDeLectador> erroresPorLinea = new ConcurrentHashMap<Integer, ErrorDeLectador>();

	public OyenteDeLinea oyenteDeLinea;

	public interface FuenteDeLineas {
		int totalLineas();

		String obtenerLinea(int indice);

		String obtenerLineaSincrona(int indice);
	}

	public interface OyenteDeLinea {
		void lineaSeleccionada(int linea);
	}

	public VisorLogVirtual() {
		setOpaque(true);
		setAutoscrolls(true);
		setFocusable(true);

		addMouseListener(new MouseAdapter() {
			@Override
			public void mousePressed(MouseEvent e) {
				requestFocusInWindow();

				int linea = lineaDesdeY(e.getY());

				if (linea < 0) {
					return;
				}

				if ((e.getModifiersEx() & InputEvent.SHIFT_DOWN_MASK) != 0 && lineaSeleccionInicio >= 0) {
					lineaSeleccionFin = linea;
				} else {
					lineaSeleccionInicio = linea;
					lineaSeleccionFin = linea;
				}

				arrastrandoSeleccion = true;
				seleccionarLinea(linea, false);

				if (oyenteDeLinea != null) {
					oyenteDeLinea.lineaSeleccionada(linea);
				}

				repaint();
			}

			@Override
			public void mouseReleased(MouseEvent e) {
				arrastrandoSeleccion = false;
			}

			@Override
			public void mouseClicked(MouseEvent e) {
				requestFocusInWindow();

				int linea = lineaDesdeY(e.getY());

				if (linea < 0) {
					return;
				}

				seleccionarLinea(linea, false);

				if (oyenteDeLinea != null) {
					oyenteDeLinea.lineaSeleccionada(linea);
				}
			}
		});

		addMouseMotionListener(new MouseMotionAdapter() {
			@Override
			public void mouseDragged(MouseEvent e) {
				int linea = lineaDesdeY(e.getY());

				if (linea < 0) {
					return;
				}

				lineaSeleccionFin = linea;
				lineaSeleccionada = linea;

				Rectangle r = new Rectangle(0, linea * alturaLinea, Math.max(1, getWidth()), alturaLinea);
				scrollRectToVisible(r);

				repaint();
			}
		});

		instalarAtajosDeCopia();
	}

	public void instalarAtajosDeCopia() {
		getInputMap(WHEN_FOCUSED).put(KeyStroke.getKeyStroke(KeyEvent.VK_C, InputEvent.CTRL_DOWN_MASK), "copiar");
		getInputMap(WHEN_FOCUSED).put(KeyStroke.getKeyStroke(KeyEvent.VK_C, InputEvent.META_DOWN_MASK), "copiar");

		getActionMap().put("copiar", new AbstractAction() {
			private static final long serialVersionUID = 1L;

			@Override
			public void actionPerformed(java.awt.event.ActionEvent e) {
				copiarSeleccionAlPortapapeles();
			}
		});
	}

	public void copiarSeleccionAlPortapapeles() {
		if (fuente == null) {
			return;
		}

		int total = totalLineas();

		if (total <= 0) {
			return;
		}

		int inicio;
		int fin;

		if (lineaSeleccionInicio >= 0 && lineaSeleccionFin >= 0) {
			inicio = Math.min(lineaSeleccionInicio, lineaSeleccionFin);
			fin = Math.max(lineaSeleccionInicio, lineaSeleccionFin);
		} else if (lineaSeleccionada >= 0) {
			inicio = lineaSeleccionada;
			fin = lineaSeleccionada;
		} else {
			return;
		}

		inicio = Math.max(0, Math.min(inicio, total - 1));
		fin = Math.max(0, Math.min(fin, total - 1));

		StringBuilder sb = new StringBuilder();

		for (int i = inicio; i <= fin; i++) {
			String linea = fuente.obtenerLineaSincrona(i);

			if (linea == null) {
				linea = "";
			}

			sb.append(linea);

			if (i < fin) {
				sb.append(System.lineSeparator());
			}
		}

		StringSelection seleccion = new StringSelection(sb.toString());
		Toolkit.getDefaultToolkit().getSystemClipboard().setContents(seleccion, seleccion);
	}

	public boolean lineaEstaSeleccionada(int linea) {
		if (lineaSeleccionInicio < 0 || lineaSeleccionFin < 0) {
			return linea == lineaSeleccionada;
		}

		int inicio = Math.min(lineaSeleccionInicio, lineaSeleccionFin);
		int fin = Math.max(lineaSeleccionInicio, lineaSeleccionFin);

		return linea >= inicio && linea <= fin;
	}

	public void establecerFuente(FuenteDeLineas nuevaFuente) {
		fuente = nuevaFuente;
		lineaSeleccionada = -1;
		lineaSeleccionInicio = -1;
		lineaSeleccionFin = -1;
		recalcularMedidas();
		revalidate();
		repaint();
	}

	public void establecerErrores(Map<Integer, ErrorDeLectador> nuevosErrores) {
		erroresPorLinea.clear();

		if (nuevosErrores != null) {
			erroresPorLinea.putAll(nuevosErrores);
		}

		repaint();
	}

	public void aplicarColores(Color fondo, Color texto, Color error, Color pila, Color textoSobreColor) {
		if (fondo != null) {
			colorFondo = fondo;
		}
		if (texto != null) {
			colorTexto = texto;
		}
		if (error != null) {
			colorError = error;
		}
		if (pila != null) {
			colorPila = pila;
		}
		if (textoSobreColor != null) {
			colorTextoSobreColor = textoSobreColor;
		}

		repaint();
	}

	public void recalcularMedidas() {
		FontMetrics fm = getFontMetrics(getFont());

		if (fm != null) {
			alturaLinea = Math.max(14, fm.getHeight() + 2);

			int total = totalLineas();
			int digitos = Math.max(3, String.valueOf(Math.max(1, total)).length());
			anchoNumeros = Math.max(44, fm.charWidth('0') * digitos + 18);
		}
	}

	public int totalLineas() {
		if (fuente == null) {
			return 0;
		}

		return fuente.totalLineas();
	}

	public int lineaDesdeY(int y) {
		int linea = y / Math.max(1, alturaLinea);

		if (linea < 0) {
			return 0;
		}

		int total = totalLineas();

		if (total <= 0) {
			return -1;
		}

		if (linea >= total) {
			return total - 1;
		}

		return linea;
	}

	public void seleccionarLineaPorY(int y) {
		int linea = lineaDesdeY(y);

		if (linea < 0) {
			return;
		}

		seleccionarLinea(linea, false);

		if (oyenteDeLinea != null) {
			oyenteDeLinea.lineaSeleccionada(linea);
		}
	}

	public void seleccionarLinea(int linea, boolean centrar) {
		int total = totalLineas();

		if (total <= 0) {
			lineaSeleccionada = -1;
			repaint();
			return;
		}

		if (linea < 0) {
			linea = 0;
		}

		if (linea >= total) {
			linea = total - 1;
		}

		int anterior = lineaSeleccionada;
		lineaSeleccionada = linea;

		if (lineaSeleccionInicio < 0 || lineaSeleccionFin < 0) {
			lineaSeleccionInicio = linea;
			lineaSeleccionFin = linea;
		}

		if (anterior >= 0) {
			repaint(0, anterior * alturaLinea, getWidth(), alturaLinea);
		}

		repaint(0, lineaSeleccionada * alturaLinea, getWidth(), alturaLinea);

		Rectangle r = new Rectangle(0, lineaSeleccionada * alturaLinea, Math.max(1, getWidth()), alturaLinea);

		if (centrar) {
			Rectangle visible = getVisibleRect();
			r.y = Math.max(0, r.y - visible.height / 2);
			r.height = visible.height;
		}

		scrollRectToVisible(r);
	}

	public int obtenerPrimeraLineaVisible() {
		Rectangle visible = getVisibleRect();
		return lineaDesdeY(visible.y);
	}

	public int obtenerUltimaLineaVisible() {
		Rectangle visible = getVisibleRect();
		return lineaDesdeY(visible.y + visible.height + alturaLinea);
	}

	public void repintarRangoLineas(int inicio, int fin) {
		if (inicio < 0) {
			inicio = 0;
		}

		if (fin < inicio) {
			fin = inicio;
		}

		int y = inicio * alturaLinea;
		int h = (fin - inicio + 1) * alturaLinea;

		repaint(0, y, getWidth(), h);
	}

	@Override
	public Dimension getPreferredSize() {
		int total = totalLineas();
		int alto = Math.max(1, total * Math.max(1, alturaLinea));

		return new Dimension(2000, alto);
	}

	@Override
	protected void paintComponent(Graphics g) {
		super.paintComponent(g);

		recalcularMedidas();

		int w = getWidth();
		int h = getHeight();

		g.setColor(colorFondo);
		g.fillRect(0, 0, w, h);

		g.setColor(colorFondoNumeros);
		g.fillRect(0, 0, anchoNumeros, h);

		if (fuente == null || totalLineas() <= 0) {
			return;
		}

		FontMetrics fm = g.getFontMetrics(getFont());

		Rectangle clip = g.getClipBounds();

		if (clip == null) {
			clip = new Rectangle(0, 0, w, h);
		}

		int primera = Math.max(0, clip.y / alturaLinea);
		int ultima = Math.min(totalLineas() - 1, (clip.y + clip.height) / alturaLinea + 1);

		int baseTextoExtra = (alturaLinea + fm.getAscent() - fm.getDescent()) / 2;

		for (int i = primera; i <= ultima; i++) {
			int y = i * alturaLinea;
			String linea = fuente.obtenerLinea(i);

			Color fondoLinea = colorFondo;
			Color textoLinea = colorTexto;

			ErrorDeLectador error = erroresPorLinea.get(Integer.valueOf(i));

			if (error != null) {
				textoLinea = error.obtenerColor();
			} else if (lineaTienePilaTexto(linea)) {
				textoLinea = colorPila;
			} else if (lineaTieneErrorTexto(linea)) {
				textoLinea = colorError;
			} else if (lineaTieneAdvertenciaTexto(linea)) {
				textoLinea = colorAdvertencia;
			}

			if (lineaEstaSeleccionada(i)) {
				fondoLinea = colorSeleccionPara(colorFondo);
			}

			g.setColor(fondoLinea);
			g.fillRect(anchoNumeros, y, w - anchoNumeros, alturaLinea);

			g.setColor(colorTextoNumeros);
			String numero = String.valueOf(i + 1);
			int anchoNumeroTexto = fm.stringWidth(numero);
			g.drawString(numero, anchoNumeros - margenDerechoNumero - anchoNumeroTexto, y + baseTextoExtra);

			g.setColor(textoLinea);

			if (linea == null) {
				linea = "";
			}

			g.drawString(linea, anchoNumeros + margenIzquierdo, y + baseTextoExtra);
		}
	}

	public Color colorTextoParaFondoEspecial(Color fondo) {
		if (usarTextoAutomaticoSobreColores) {
			return colorTextoLegiblePara(fondo);
		}

		return colorTextoSobreColor;
	}

	public Color colorSeleccionPara(Color colorBase) {
		if (colorBase == null) {
			return colorSeleccion;
		}

		int brillo = (colorBase.getRed() + colorBase.getGreen() + colorBase.getBlue()) / 3;

		// Si el fondo es oscuro, aclarar la selección.
		// Si el fondo ya es claro, oscurecerla para que siga viéndose.
		if (brillo < 90) {
			return aclararColor(colorBase, 70);
		}

		return oscurecerColor(colorBase, 45);
	}

	public Color aclararColor(Color color, int cantidad) {
		int r = Math.min(255, color.getRed() + cantidad);
		int g = Math.min(255, color.getGreen() + cantidad);
		int b = Math.min(255, color.getBlue() + cantidad);

		return new Color(r, g, b);
	}

	public Color oscurecerColor(Color color, int cantidad) {
		int r = Math.max(0, color.getRed() - cantidad);
		int g = Math.max(0, color.getGreen() - cantidad);
		int b = Math.max(0, color.getBlue() - cantidad);

		return new Color(r, g, b);
	}

	@Override
	public Dimension getPreferredScrollableViewportSize() {
		return new Dimension(800, 500);
	}

	@Override
	public int getScrollableUnitIncrement(Rectangle visibleRect, int orientation, int direction) {
		if (orientation == SwingConstants.VERTICAL) {
			return alturaLinea;
		}

		return 40;
	}

	@Override
	public int getScrollableBlockIncrement(Rectangle visibleRect, int orientation, int direction) {
		if (orientation == SwingConstants.VERTICAL) {
			return Math.max(alturaLinea, visibleRect.height - alturaLinea);
		}

		return Math.max(40, visibleRect.width - 40);
	}

	@Override
	public boolean getScrollableTracksViewportWidth() {
		return false;
	}

	@Override
	public boolean getScrollableTracksViewportHeight() {
		return false;
	}

	public void ejecutarEnEDT(Runnable r) {
		if (SwingUtilities.isEventDispatchThread()) {
			r.run();
		} else {
			SwingUtilities.invokeLater(r);
		}
	}

	public boolean lineaTieneErrorTexto(String linea) {
		if (linea == null) {
			return false;
		}

		String s = linea.toUpperCase();

		return s.contains("ERROR") || s.contains("EXCEPTION") || s.contains("SEVERE") || s.contains("FATAL");
	}

	public boolean lineaTieneAdvertenciaTexto(String linea) {
		if (linea == null) {
			return false;
		}

		String s = linea.toUpperCase();

		return s.contains("WARN") || s.contains("WARNING") || s.contains("ADVERTENCIA");
	}

	public boolean lineaTienePilaTexto(String linea) {
		if (linea == null) {
			return false;
		}

		String s = linea.trim();

		return s.equals("STACKTRACE") || s.contains("STACKTRACE") || s.startsWith("at ") || s.startsWith("at\t")
				|| s.startsWith("Caused by:") || s.startsWith("Suppressed:") || s.startsWith("... ")
				|| s.contains(" at ") || s.contains("\tat ");
	}

	public Color colorTextoLegiblePara(Color fondo) {
		if (fondo == null) {
			return colorTexto;
		}

		int r = fondo.getRed();
		int g = fondo.getGreen();
		int b = fondo.getBlue();

		int luminancia = (int) ((r * 0.299) + (g * 0.587) + (b * 0.114));

		if (luminancia < 140) {
			return Color.WHITE;
		}

		return Color.BLACK;
	}
}package com.asbestosstar.crashdetector.gui.elementos;

import java.awt.Color;
import java.util.HashSet;
import java.util.Set;

import javax.swing.JTextPane;
import javax.swing.text.BadLocationException;
import javax.swing.text.DefaultStyledDocument;
import javax.swing.text.Style;
import javax.swing.text.StyleConstants;
import javax.swing.text.StyledDocument;

public class LectadorDeCodigo extends JTextPane {

	private static final long serialVersionUID = 1L;

	private Color colorFondo;
	private Color colorTextoNormal;
	private Color colorPalabraClave;
	private Color colorCadena;
	private Color colorComentario;
	private Color colorNumero;
	private Color colorTipo;
	private Color colorMetodo;

	private final Set<String> palabrasClave = new HashSet<String>();
	private final Set<String> tipos = new HashSet<String>();

	public LectadorDeCodigo(Color colorFondo, Color colorTextoNormal, Color colorPalabraClave, Color colorCadena,
			Color colorComentario, Color colorNumero, Color colorTipo, Color colorMetodo) {

		super(new DefaultStyledDocument());

		this.colorFondo = colorFondo;
		this.colorTextoNormal = colorTextoNormal;
		this.colorPalabraClave = colorPalabraClave;
		this.colorCadena = colorCadena;
		this.colorComentario = colorComentario;
		this.colorNumero = colorNumero;
		this.colorTipo = colorTipo;
		this.colorMetodo = colorMetodo;

		inicializarPalabras();

		setEditable(false);
		setBackground(colorFondo);
		setForeground(colorTextoNormal);
		setCaretColor(colorTextoNormal);
		setFont(new java.awt.Font(java.awt.Font.MONOSPACED, java.awt.Font.PLAIN, 13));
	}

	private void inicializarPalabras() {
		String[] claves = new String[] { "abstract", "assert", "break", "case", "catch", "class", "const", "continue",
				"default", "do", "else", "enum", "extends", "final", "finally", "for", "goto", "if", "implements",
				"import", "instanceof", "interface", "native", "new", "package", "private", "protected", "public",
				"return", "static", "strictfp", "super", "switch", "synchronized", "this", "throw", "throws",
				"transient", "try", "volatile", "while" };

		for (String s : claves) {
			palabrasClave.add(s);
		}

		String[] tiposBase = new String[] { "boolean", "byte", "char", "double", "float", "int", "long", "short",
				"void", "String", "Object", "Integer", "Long", "Double", "Float", "Boolean", "Character", "Byte",
				"Short", "List", "Map", "Set", "Collection", "ArrayList", "HashMap", "HashSet" };

		for (String s : tiposBase) {
			tipos.add(s);
		}
	}

	public void establecerColores(Color colorFondo, Color colorTextoNormal, Color colorPalabraClave, Color colorCadena,
			Color colorComentario, Color colorNumero, Color colorTipo, Color colorMetodo) {

		this.colorFondo = colorFondo;
		this.colorTextoNormal = colorTextoNormal;
		this.colorPalabraClave = colorPalabraClave;
		this.colorCadena = colorCadena;
		this.colorComentario = colorComentario;
		this.colorNumero = colorNumero;
		this.colorTipo = colorTipo;
		this.colorMetodo = colorMetodo;

		setBackground(colorFondo);
		setForeground(colorTextoNormal);
		setCaretColor(colorTextoNormal);

		aplicarResaltado();
	}

	public void establecerCodigo(String codigo) {
		if (codigo == null) {
			codigo = "";
		}

		setText(codigo);
		aplicarResaltado();
		setCaretPosition(0);
	}

	private void aplicarResaltado() {
		StyledDocument doc = getStyledDocument();

		String texto;

		try {
			texto = doc.getText(0, doc.getLength());
		} catch (BadLocationException e) {
			return;
		}

		aplicarEstilo(doc, 0, texto.length(), colorTextoNormal, false);

		int i = 0;

		while (i < texto.length()) {
			char c = texto.charAt(i);

			if (c == '/' && i + 1 < texto.length() && texto.charAt(i + 1) == '/') {
				int inicio = i;
				i += 2;

				while (i < texto.length() && texto.charAt(i) != '\n') {
					i++;
				}

				aplicarEstilo(doc, inicio, i - inicio, colorComentario, false);
				continue;
			}

			if (c == '/' && i + 1 < texto.length() && texto.charAt(i + 1) == '*') {
				int inicio = i;
				i += 2;

				while (i + 1 < texto.length() && !(texto.charAt(i) == '*' && texto.charAt(i + 1) == '/')) {
					i++;
				}

				if (i + 1 < texto.length()) {
					i += 2;
				}

				aplicarEstilo(doc, inicio, i - inicio, colorComentario, false);
				continue;
			}

			if (c == '"' || c == '\'') {
				char comilla = c;
				int inicio = i;
				i++;

				boolean escape = false;

				while (i < texto.length()) {
					char actual = texto.charAt(i);

					if (escape) {
						escape = false;
					} else if (actual == '\\') {
						escape = true;
					} else if (actual == comilla) {
						i++;
						break;
					}

					i++;
				}

				aplicarEstilo(doc, inicio, i - inicio, colorCadena, false);
				continue;
			}

			if (Character.isDigit(c)) {
				int inicio = i;
				i++;

				while (i < texto.length()) {
					char actual = texto.charAt(i);

					if (Character.isDigit(actual) || actual == '.' || actual == 'x' || actual == 'X' || actual == 'L'
							|| actual == 'l' || actual == 'F' || actual == 'f' || actual == 'D' || actual == 'd'
							|| actual == '_') {
						i++;
					} else {
						break;
					}
				}

				aplicarEstilo(doc, inicio, i - inicio, colorNumero, false);
				continue;
			}

			if (Character.isJavaIdentifierStart(c)) {
				int inicio = i;
				i++;

				while (i < texto.length() && Character.isJavaIdentifierPart(texto.charAt(i))) {
					i++;
				}

				String palabra = texto.substring(inicio, i);

				if (palabrasClave.contains(palabra)) {
					aplicarEstilo(doc, inicio, i - inicio, colorPalabraClave, true);
				} else if (tipos.contains(palabra) || Character.isUpperCase(palabra.charAt(0))) {
					aplicarEstilo(doc, inicio, i - inicio, colorTipo, false);
				} else if (esMetodo(texto, i)) {
					aplicarEstilo(doc, inicio, i - inicio, colorMetodo, false);
				}

				continue;
			}

			i++;
		}
	}

	private boolean esMetodo(String texto, int indiceDespuesPalabra) {
		int i = indiceDespuesPalabra;

		while (i < texto.length() && Character.isWhitespace(texto.charAt(i))) {
			i++;
		}

		return i < texto.length() && texto.charAt(i) == '(';
	}

	private void aplicarEstilo(StyledDocument doc, int inicio, int longitud, Color color, boolean negrita) {
		if (longitud <= 0) {
			return;
		}

		Style estilo = addStyle("estilo_" + color.getRGB() + "_" + negrita, null);
		StyleConstants.setForeground(estilo, color);
		StyleConstants.setBold(estilo, negrita);

		doc.setCharacterAttributes(inicio, longitud, estilo, true);
	}
}package com.asbestosstar.crashdetector.gui.elementos;

import java.awt.Color;
import java.awt.Dimension;
import java.awt.FontMetrics;
import java.awt.Graphics;
import java.awt.Rectangle;

import javax.swing.JList;
import javax.swing.JPanel;
import javax.swing.event.ListDataEvent;
import javax.swing.event.ListDataListener;

/**
 * Panel lateral que dibuja números de línea junto a un JList<String>. Diseñado
 * para ser rápido con ficheros grandes — dibuja solo las filas visibles y
 * recalcula su ancho cuando cambia el modelo.
 */
public class NumeradorDeLineas extends JPanel {
	private final JList<String> lista;
	private int anchoCache = -1;

	public NumeradorDeLineas(JList<String> lista) {
		this.lista = lista;
		setBackground(new Color(25, 25, 25));
		setForeground(Color.LIGHT_GRAY);
		setFont(lista.getFont());

		// Escuchar cambios en el modelo para actualizar tamaño/repintado
		lista.getModel().addListDataListener(new ListDataListener() {
			@Override
			public void contentsChanged(ListDataEvent e) {
				recalcularYActualizar();
			}

			@Override
			public void intervalAdded(ListDataEvent e) {
				recalcularYActualizar();
			}

			@Override
			public void intervalRemoved(ListDataEvent e) {
				recalcularYActualizar();
			}
		});

		// También cuando la fuente cambia en la lista (por si acaso)
		lista.addPropertyChangeListener("font", evt -> {
			setFont(lista.getFont());
			recalcularYActualizar();
		});

		// Forzar primera medida
		recalcularYActualizar();
	}

	private void recalcularYActualizar() {
		anchoCache = -1; // forzar recálculo en getPreferredSize()
		revalidate();
		repaint();
	}

	@Override
	public Dimension getPreferredSize() {
		int lineas = lista.getModel().getSize();
		int digitos = Math.min(6, Math.max(3, String.valueOf(Math.max(1, lineas)).length()));
		FontMetrics fm = getFontMetrics(getFont());
		int ancho = fm.charWidth('0') * digitos + 10; // margen
		return new Dimension(ancho, Integer.MAX_VALUE);
	}

	@Override
	protected void paintComponent(Graphics g) {
		super.paintComponent(g);
		// fondo
		g.setColor(getBackground());
		g.fillRect(0, 0, getWidth(), getHeight());

		// si no hay nada visible, no dibujamos
		int primero = lista.getFirstVisibleIndex();
		int ultimo = lista.getLastVisibleIndex();
		if (primero == -1 || ultimo == -1) {
			return;
		}

		FontMetrics fm = g.getFontMetrics(lista.getFont());
		int alturaLinea;
		// preferir fixedCellHeight si está establecido (mejor rendimiento)
		int fixedH = lista.getFixedCellHeight();
		if (fixedH > 0) {
			alturaLinea = fixedH;
		} else {
			// intentar obtener altura por bounds de la primera celda visible
			Rectangle r = lista.getCellBounds(primero, primero);
			alturaLinea = (r != null) ? r.height : fm.getHeight();
		}

		// posición X base para alinear a la derecha
		int anchoPreferido = getPreferredSize().width;
		int baseX = anchoPreferido - 5;

		// dibujar números de línea para cada celda visible
		for (int i = primero; i <= ultimo; i++) {
			Rectangle bounds = lista.getCellBounds(i, i);
			if (bounds == null)
				continue;

			// calcular baseline vertical para texto (centrado verticalmente dentro de la
			// celda)
			int y = bounds.y + (bounds.height + fm.getAscent() - fm.getDescent()) / 2;

			String texto = String.valueOf(i + 1);
			int textWidth = fm.stringWidth(texto);

			g.setColor(getForeground());
			g.drawString(texto, baseX - textWidth, y);
		}
	}
}
package com.asbestosstar.crashdetector.gui.elementos;

import java.awt.Color;
import java.awt.Component;
import java.awt.Image;
import java.io.File;
import java.util.LinkedHashMap;
import java.util.Map;

import javax.swing.Icon;
import javax.swing.ImageIcon;
import javax.swing.JComboBox;
import javax.swing.JLabel;
import javax.swing.JList;
import javax.swing.plaf.basic.BasicComboBoxRenderer;

import com.asbestosstar.crashdetector.Statics;

/**
 * ComboBox que muestra una bandera o icono junto al nombre del idioma. Las
 * rutas de los iconos se proporcionan completas en el mapa (por ejemplo
 * "imagenes/bandera_mexico.png").
 */
public class ComboIdiomasConIcono extends JComboBox<String> {

	private final Map<String, Icon> iconosPorEtiqueta;
	private int anchoIcono = 18;
	private int altoIcono = 12;
	private int separacionIconoTexto = 8;

	public ComboIdiomasConIcono(LinkedHashMap<String, String> etiquetaARuta) {
		super(etiquetaARuta.keySet().toArray(new String[0]));
		this.iconosPorEtiqueta = new LinkedHashMap<>();

		for (Map.Entry<String, String> e : etiquetaARuta.entrySet()) {
			iconosPorEtiqueta.put(e.getKey(), cargarIconoLocal(e.getValue(), anchoIcono, altoIcono));
		}

		setRenderer(new Renderizador());
		setFocusable(true);
	}

	public void aplicarColores(Color fondo, Color texto) {
		setBackground(fondo);
		setForeground(texto);
		Component c = getEditor() != null ? getEditor().getEditorComponent() : null;
		if (c != null) {
			c.setBackground(fondo);
			c.setForeground(texto);
		}
	}

	private Icon cargarIconoLocal(String rutaRelativa, int w, int h) {
		try {
			File archivo = Statics.carpeta.resolve(rutaRelativa).toFile();
			if (!archivo.exists())
				return null;
			ImageIcon base = new ImageIcon(archivo.getAbsolutePath());
			if (base.getIconWidth() <= 0 || base.getIconHeight() <= 0)
				return base;
			Image img = base.getImage().getScaledInstance(w, h, Image.SCALE_SMOOTH);
			return new ImageIcon(img);
		} catch (Throwable t) {
			return null;
		}
	}

	private class Renderizador extends BasicComboBoxRenderer {
		@Override
		@SuppressWarnings("rawtypes")
		public Component getListCellRendererComponent(JList lista, Object valor, int indice, boolean seleccionado,
				boolean foco) {
			JLabel lbl = (JLabel) super.getListCellRendererComponent(lista, valor, indice, seleccionado, foco);
			String etiqueta = valor != null ? valor.toString() : "";
			Icon icono = iconosPorEtiqueta.get(etiqueta);

			lbl.setIcon(icono);
			lbl.setText(etiqueta);
			lbl.setIconTextGap(separacionIconoTexto);
			lbl.setHorizontalAlignment(LEFT);
			lbl.setOpaque(true);

			if (seleccionado) {
				lbl.setBackground(lista.getSelectionBackground());
				lbl.setForeground(lista.getSelectionForeground());
			} else {
				lbl.setBackground(lista.getBackground());
				lbl.setForeground(lista.getForeground());
			}

			int altoFila = Math.max(lista.getFixedCellHeight() > 0 ? lista.getFixedCellHeight() : 0,
					Math.max(lbl.getFontMetrics(lbl.getFont()).getHeight(), altoIcono) + 4);
			if (lista.getFixedCellHeight() <= 0) {
				lista.setFixedCellHeight(altoFila);
			}
			return lbl;
		}
	}
}
