		JButton boton = new JButton(TipoGUI.ACTUALIZADOR_MODS.etiquetaDelBoton());
		boton.setAlignmentX(Component.LEFT_ALIGNMENT);
		boton.setMaximumSize(new Dimension(Integer.MAX_VALUE, 28));
