	public void recargarApariencia() {
		aplicarApariencia();
	}

	@Override
	public boolean puedeEditarApariencia() {
		return true;
	}

	@Override
	public TipoGUI<HistoriaDeModsGUI> tipo() {
		return TipoGUI.HISTORIA_DE_MODS;
	}

	@Override
	public abstract void init();

	@Override
	public abstract String id();

