public abstract class DerechosPiratasGUI extends JDialog implements CrashDetectorGUI, BotonDeBarraLateralDerecha {

	private static final long serialVersionUID = 1L;

	public static Map<String, Supplier<DerechosPiratasGUI>> GUIS = new HashMap<String, Supplier<DerechosPiratasGUI>>();

	public final Path archivo = Statics.carpeta.resolve("derechos_piratas.json");

	/** mapa codigo_idioma -> html */
	public final Map<String, String> derechos = new HashMap<String, String>();

	public void cargarDatos() {
		derechos.clear();
		if (!Files.exists(archivo)) {
			return;
		}

		try {
			String json = new String(Files.readAllBytes(archivo), StandardCharsets.UTF_8);
			if (json == null || json.trim().isEmpty()) {
				return;
			}

			Nodo raiz = Json.leer(json);
			if (!raiz.esObjeto()) {
				return;
			}

			for (String k : raiz.claves()) {
				Nodo v = raiz.obtener(k);
				if (v != null && !v.esObjeto() && !v.esArreglo()) {
					String txt = v.comoCadena();
					if (txt != null && !txt.trim().isEmpty()) {
						derechos.put(k, txt);
					}
				}
			}
		} catch (Exception ignored) {
		}
	}

	public void guardarDatos() {
		try {
			Nodo raiz = Json.crearObjeto();

			for (Map.Entry<String, String> e : derechos.entrySet()) {
				if (e.getKey() == null) {
					continue;
				}

				String codigo = e.getKey().trim();
				if (codigo.isEmpty()) {
					continue;
				}

				String v = e.getValue();
				if (v == null) {
					continue;
				}

				v = v.trim();
				if (v.isEmpty()) {
					continue;
				}

				raiz.obtener(codigo).poner(v);
			}

			Files.write(archivo, raiz.aBytesUtf8());
		} catch (IOException ignored) {
		}

		dispose();
	}

	@Override
	public TipoGUI tipo() {
		return TipoGUI.MIRANDA;
	}

	/**
	 * Convierte el nombre visible del idioma a su código usando el registro
	 * dinámico actual.
	 */
	public String obtenerCodigoIdiomaDinamico(String nombreVisible) {
		return Idioma.codigoDesdeNombreVisible(nombreVisible);
	}

	public void forzarFondo(JComponent c, Color fondo) {
		if (c == null) {
			return;
		}
		c.setOpaque(true);
		c.setBackground(fondo);
	}

	/**
	 * En macOS conviene usar una fuente más segura que Segoe UI, porque Aqua a
	 * veces combina peor tamaños/preferencias con fuentes no nativas.
	 */
	public Font fuenteUI(int estilo, int tam) {
		if (CrashDetectorGUI.esMac()) {
			return new Font("SansSerif", estilo, tam);
		}
		return new Font("Segoe UI", estilo, tam);
	}

	/**
	 * Crea un JTextArea con tamaño explícito para evitar que en macOS colapse a una
	 * altura casi nula dentro de GridBagLayout.
	 */
	public JTextArea crearAreaMultilinea(String textoInicial, Color fondo, Color texto) {
		JTextArea area = new JTextArea(textoInicial != null ? textoInicial : "");
		area.setLineWrap(true);
		area.setWrapStyleWord(true);
		area.setFont(fuenteUI(Font.PLAIN, 13));
		area.setBackground(fondo);
		area.setForeground(texto);
		area.setCaretColor(texto);

		// Filas/columnas para que el preferred size no dependa del LAF.
		area.setRows(CrashDetectorGUI.esMac() ? 5 : 4);
		area.setColumns(32);

		// En macOS hacemos aún más explícito el tamaño.
		if (CrashDetectorGUI.esMac()) {
			area.setMinimumSize(new Dimension(320, 96));
			area.setPreferredSize(new Dimension(480, 110));
		}

		return area;
	}

	/**
	 * Crea un JScrollPane robusto para macOS, forzando viewport opaco y tamaño
	 * mínimo.
	 */
	public JScrollPane crearScrollRobusto(JTextArea area, Color fondoScroll, Color borde) {
		JScrollPane scroll = new JScrollPane(area);
		scroll.setBorder(BorderFactory.createLineBorder(borde, 1));
		scroll.getViewport().setOpaque(true);
		scroll.getViewport().setBackground(fondoScroll);
		scroll.setOpaque(true);
		scroll.setBackground(fondoScroll);

		if (CrashDetectorGUI.esMac()) {
			scroll.setMinimumSize(new Dimension(360, 110));
			scroll.setPreferredSize(new Dimension(520, 120));
		}

		return scroll;
	}

	/**
	 * Estiliza un botón de forma más determinista para macOS.
	 */
	public void estilizarBoton(JButton boton, Color fondo, Color texto) {
		if (boton == null) {
			return;
		}

		boton.setFont(fuenteUI(Font.BOLD, 12));
		boton.setOpaque(true);
		boton.setBackground(fondo);
		boton.setForeground(texto);
		boton.setFocusPainted(false);
		boton.setBorderPainted(true);

		if (CrashDetectorGUI.esMac()) {
			boton.setContentAreaFilled(true);
			boton.setMinimumSize(new Dimension(110, 32));
			boton.setPreferredSize(new Dimension(130, 34));
		}
	}

	/**
	 * Fuerza colores/opacidad recursivamente también en componentes que en macOS
	 * suelen quedar “transparentes” o visualmente incoherentes.
	 */
	public void aplicarTemaRecursivo(Component c, Color fondoBase, Color textoBase) {
		if (c == null) {
			return;
		}

		if (c instanceof JPanel || c instanceof JViewport) {
			c.setBackground(fondoBase);
			if (c instanceof JComponent) {
				((JComponent) c).setOpaque(true);
			}
		}

		if (c instanceof JLabel) {
			c.setForeground(textoBase);
			if (c instanceof JComponent) {
				((JComponent) c).setOpaque(false);
			}
		}

		if (c instanceof JButton) {
			JButton b = (JButton) c;
			b.setOpaque(true);
			if (CrashDetectorGUI.esMac()) {
				b.setContentAreaFilled(true);
			}
		}

		if (c instanceof JScrollPane) {
			JScrollPane sp = (JScrollPane) c;
			sp.setOpaque(true);
			sp.setBackground(fondoBase);
			sp.getViewport().setOpaque(true);
			sp.getViewport().setBackground(fondoBase);
		}

		if (c instanceof java.awt.Container) {
			for (Component hijo : ((java.awt.Container) c).getComponents()) {
				aplicarTemaRecursivo(hijo, fondoBase, textoBase);
			}
		}
	}

	/**
	 * Editor multilenguaje HTML robusto para Linux y macOS.
	 */
	public void editarDerechosMultilenguaje(String titulo, Color fondo, Color texto, Color caja, Color borde) {
		if (derechos == null) {
			return;
		}

		JDialog dialogo = new JDialog(this, titulo, true);
		dialogo.setLayout(new BorderLayout(10, 10));

		// En macOS conviene usar dimensiones algo mayores para evitar recortes.
		if (CrashDetectorGUI.esMac()) {
			dialogo.setSize(860, 620);
			dialogo.setMinimumSize(new Dimension(760, 520));
		} else {
			dialogo.setSize(760, 520);
		}

		JPanel panelCampos = new JPanel(new GridBagLayout());
		panelCampos.setBorder(BorderFactory.createEmptyBorder(10, 10, 10, 10));
		panelCampos.setBackground(fondo);
		panelCampos.setOpaque(true);

		java.awt.GridBagConstraints gbc = new java.awt.GridBagConstraints();
		gbc.insets = new java.awt.Insets(6, 6, 6, 6);
		gbc.fill = java.awt.GridBagConstraints.BOTH;
		gbc.anchor = java.awt.GridBagConstraints.NORTHWEST;

		LinkedHashMap<String, String> idiomas = Idioma.mapaParaComboBoxIdiomas();
		Map<String, JTextArea> campos = new LinkedHashMap<String, JTextArea>();

		int fila = 0;

		// Idiomas registrados dinámicamente
		for (Entry<String, String> entry : idiomas.entrySet()) {
			String nombreVisible = entry.getKey();
			String rutaBandera = entry.getValue();
			String codigo = obtenerCodigoIdiomaDinamico(nombreVisible);

			if (codigo == null || codigo.trim().isEmpty()) {
				continue;
			}

			JLabel etiqueta = new JLabel(codigo);
			etiqueta.setFont(fuenteUI(Font.BOLD, 12));
			etiqueta.setForeground(texto);

			try {
				if (rutaBandera != null) {
					File f = Statics.carpeta.resolve(rutaBandera).toFile();
					if (f.exists()) {
						ImageIcon ic = new ImageIcon(f.getAbsolutePath());
						Image img = ic.getImage().getScaledInstance(18, 12, Image.SCALE_SMOOTH);
						etiqueta.setIcon(new ImageIcon(img));
						etiqueta.setIconTextGap(8);
					}
				}
			} catch (Exception ignored) {
			}

			gbc.gridx = 0;
			gbc.gridy = fila;
			gbc.weightx = 0.15;
			gbc.weighty = 0.0;
			panelCampos.add(etiqueta, gbc);

			JTextArea area = crearAreaMultilinea(derechos.getOrDefault(codigo, ""), caja, texto);
			JScrollPane scroll = crearScrollRobusto(area, caja, borde);

			gbc.gridx = 1;
			gbc.weightx = 0.85;
			gbc.weighty = 0.0;
			panelCampos.add(scroll, gbc);

			campos.put(codigo, area);
			fila++;
		}

		// Códigos extra ya presentes en el JSON
		for (Entry<String, String> extra : derechos.entrySet()) {
			String codigo = extra.getKey();

			if (codigo == null || codigo.trim().isEmpty() || campos.containsKey(codigo)) {
				continue;
			}

			JLabel etiqueta = new JLabel(codigo);
			etiqueta.setFont(fuenteUI(Font.BOLD, 12));
			etiqueta.setForeground(texto);

			gbc.gridx = 0;
			gbc.gridy = fila;
			gbc.weightx = 0.15;
			gbc.weighty = 0.0;
			panelCampos.add(etiqueta, gbc);

			JTextArea area = crearAreaMultilinea(extra.getValue(), caja, texto);
			JScrollPane scroll = crearScrollRobusto(area, caja, borde);

			gbc.gridx = 1;
			gbc.weightx = 0.85;
			gbc.weighty = 0.0;
			panelCampos.add(scroll, gbc);

			campos.put(codigo, area);
			fila++;
		}

		// Empujador final para que GridBag no “aplast[e]” filas arriba en algunos LAF.
		JPanel relleno = new JPanel();
		relleno.setOpaque(true);
		relleno.setBackground(fondo);

		gbc.gridx = 0;
		gbc.gridy = fila;
		gbc.gridwidth = 2;
		gbc.weightx = 1.0;
		gbc.weighty = 1.0;
		panelCampos.add(relleno, gbc);

		JPanel botones = new JPanel(new FlowLayout(FlowLayout.RIGHT));
		botones.setBackground(fondo);
		botones.setOpaque(true);

		JButton ok = new JButton(MonitorDePID.idioma.aceptar());
		JButton cancel = new JButton(MonitorDePID.idioma.cancelar());

		estilizarBoton(ok, borde, Color.BLACK);
		estilizarBoton(cancel, borde, Color.BLACK);

		ok.addActionListener(e -> {
			derechos.clear();

			for (Entry<String, JTextArea> c : campos.entrySet()) {
				String v = c.getValue().getText().trim();
				if (!v.isEmpty()) {
					derechos.put(c.getKey(), v);
				}
			}

			String textoCoreano = derechos.get("ko");
			if (textoCoreano != null && !textoCoreano.isEmpty()) {
				com.asbestosstar.crashdetector.idioma.cumplimiento.ActaDeProteccionDelIdiomaCulturalDePyongyang
						.contieneJergaSur(textoCoreano);
			}

			dialogo.dispose();
		});

		cancel.addActionListener(e -> dialogo.dispose());

		botones.add(ok);
		botones.add(cancel);

		JScrollPane scrollPrincipal = new JScrollPane(panelCampos);
		scrollPrincipal.setBorder(BorderFactory.createEmptyBorder());
		scrollPrincipal.setOpaque(true);
		scrollPrincipal.setBackground(fondo);
		scrollPrincipal.getViewport().setOpaque(true);
		scrollPrincipal.getViewport().setBackground(fondo);

		dialogo.add(scrollPrincipal, BorderLayout.CENTER);
		dialogo.add(botones, BorderLayout.SOUTH);

		aplicarTemaRecursivo(dialogo.getContentPane(), fondo, texto);

		dialogo.setLocationRelativeTo(this);
		dialogo.setVisible(true);
	}
}package com.asbestosstar.crashdetector.gui.tipos.quickfix;

import java.awt.BorderLayout;
import java.awt.Image;
import java.io.File;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.function.Supplier;

import javax.imageio.ImageIO;
import javax.swing.ImageIcon;
import javax.swing.JFrame;
import javax.swing.JLabel;
import javax.swing.JPanel;
import javax.swing.JScrollPane;
import javax.swing.JSeparator;

import com.asbestosstar.crashdetector.CrashDetectorLogger;
import com.asbestosstar.crashdetector.analizador.QuickFix;
import com.asbestosstar.crashdetector.gui.CrashDetectorGUI;
import com.asbestosstar.crashdetector.gui.elementos.BotonDeBarraLateralDerecha;
import com.asbestosstar.crashdetector.gui.tipos.TipoGUI;

/**
 * Ventana base abstracta para mostrar múltiples QuickFix.
 *
 * RESPONSABILIDADES EXCLUSIVAS: - Gestionar ventana (JFrame) - Gestionar scroll
 * - Gestionar inserción y limpieza de QuickFix
 *
 *
 * Toda la apariencia pertenece a la implementación concreta.
 */
public abstract class TodosQuickFixesGUI extends JFrame implements CrashDetectorGUI, BotonDeBarraLateralDerecha {

	private static final long serialVersionUID = 1L;

	/** Registro global de GUIs */
	public static Map<String, Supplier<TodosQuickFixesGUI>> GUIS = new HashMap<>();

	// ===== Estructura técnica =====
	protected JScrollPane scroll;
	protected JPanel panelContenedor;
	protected JPanel piePanel;

	// ===== API pública =====

	/**
	 * Añade un QuickFix justo antes del pie.
	 */
	public void agregarQuickFix(QuickFix quickFix) {
		if (panelContenedor == null || piePanel == null) {
			CrashDetectorLogger.log("QuickFix: contenedor no inicializado");
			return;
		}

		int indicePie = panelContenedor.getComponentCount() - 1;

		// Separador lógico (apariencia definida por la implementación)
		if (indicePie > 0) {
			panelContenedor.add(new JSeparator(), indicePie);
			indicePie++;
		}

		panelContenedor.add(new ElementoQuickFix(quickFix), indicePie);
		panelContenedor.revalidate();
		panelContenedor.repaint();
	}

	/**
	 * Elimina todos los QuickFix y deja solo el pie.
	 */
	public void limpiar() {
		if (panelContenedor == null || piePanel == null)
			return;

		panelContenedor.removeAll();
		panelContenedor.add(piePanel);
		panelContenedor.revalidate();
		panelContenedor.repaint();
	}

	// ===== Hooks de implementación =====

	protected abstract String rutaImagenPie();

	protected int anchoImagenPie() {
		return 128;
	}

	protected int altoImagenPie() {
		return 128;
	}

	protected String textoFallbackImagen() {
		return "(Imagen no disponible)";
	}

	/** Aplica TODA la apariencia (colores, opacidades, separadores, etc.) */
	protected abstract void aplicarApariencia();

	// ===== Utilidades =====

	protected JLabel crearEtiquetaImagenEscalada(String ruta, int w, int h) {
		try {
			Image img = ImageIO.read(new File(ruta));
			Image esc = img.getScaledInstance(w, h, Image.SCALE_SMOOTH);
			return new JLabel(new ImageIcon(esc));
		} catch (IOException e) {
			return null;
		}
	}

	/**
	 * Configuración mínima de la ventana. La implementación puede modificar lo que
	 * quiera después.
	 */
	protected void configurarVentanaBase() {
		setTitle("QuickFix");
		setSize(720, 520);
		setLocationRelativeTo(null);
		setDefaultCloseOperation(JFrame.DISPOSE_ON_CLOSE);
		setLayout(new BorderLayout());
	}

	// ===== CrashDetectorGUI =====

	@Override
	public void recargarApariencia() {
		aplicarApariencia();
	}

	@Override
	public final TipoGUI<TodosQuickFixesGUI> tipo() {
		return TipoGUI.TODOS_QUICKFIXES;
	}

	@Override
	public abstract String id();

	@Override
	public abstract void init();
}
package com.asbestosstar.crashdetector.gui.tipos.actualizador;

import java.awt.BorderLayout;
import java.awt.Dimension;
import java.awt.FlowLayout;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.function.Supplier;

import javax.swing.JButton;
import javax.swing.JFrame;
import javax.swing.JLabel;
import javax.swing.JOptionPane;
import javax.swing.JPanel;
import javax.swing.JScrollPane;
import javax.swing.JSplitPane;
import javax.swing.JTable;
import javax.swing.JTextArea;
import javax.swing.SwingWorker;
import javax.swing.table.AbstractTableModel;

import com.asbestosstar.crashdetector.CrashDetectorLogger;
import com.asbestosstar.crashdetector.MonitorDePID;
import com.asbestosstar.crashdetector.dto.modpack.tlmods.ColaActualizacionesModpack;
import com.asbestosstar.crashdetector.gui.CrashDetectorGUI;
import com.asbestosstar.crashdetector.gui.elementos.EditorBotonActualizar;
import com.asbestosstar.crashdetector.gui.elementos.RenderizadorBotonActualizar;
import com.asbestosstar.crashdetector.gui.tipos.TipoGUI;

public abstract class ActualizadorModsGUI extends JFrame implements CrashDetectorGUI {

	public static final Map<String, Supplier<ActualizadorModsGUI>> GUIS = new HashMap<>();

	public JTextArea areaDescripcion;
	public JLabel imagenTema;
	public JLabel etiquetaEstado;

	public JButton botonEscanear;
	public JButton botonActualizarTodo;

	public JTable tablaActualizaciones;
	public ModeloActualizaciones modeloActualizaciones;

	public Path carpetaInstancia;
	public List<ColaActualizacionesModpack.ActualizacionPendiente> cola = new ArrayList<>();

	public SwingWorker<Void, Void> worker;

	@Override
	public TipoGUI<ActualizadorModsGUI> tipo() {
		return TipoGUI.ACTUALIZADOR_MODS;
	}

	@Override
	public void init() {
		setTitle(MonitorDePID.idioma.actualizadorModsTitulo());
		setSize(1050, 680);
		setDefaultCloseOperation(JFrame.HIDE_ON_CLOSE);
		setLayout(new BorderLayout());

		carpetaInstancia = Paths.get(".").toAbsolutePath().normalize();

		JPanel panelIzquierdo = new JPanel(new BorderLayout(8, 8));
		panelIzquierdo.setPreferredSize(new Dimension(250, 500));

		imagenTema = new JLabel("", JLabel.CENTER);

		areaDescripcion = new JTextArea();
		areaDescripcion.setEditable(false);
		areaDescripcion.setLineWrap(true);
		areaDescripcion.setWrapStyleWord(true);
		areaDescripcion.setText(MonitorDePID.idioma.actualizadorModsDescripcion());

		panelIzquierdo.add(imagenTema, BorderLayout.NORTH);
		panelIzquierdo.add(new JScrollPane(areaDescripcion), BorderLayout.CENTER);

		JPanel panelDerecho = new JPanel(new BorderLayout(8, 8));

		JPanel barra = new JPanel(new FlowLayout(FlowLayout.LEFT, 8, 4));
		botonEscanear = new JButton(MonitorDePID.idioma.actualizadorModsBotonEscanear());
		botonActualizarTodo = new JButton(MonitorDePID.idioma.actualizadorModsBotonActualizarTodo());
		etiquetaEstado = new JLabel(MonitorDePID.idioma.actualizadorModsEstadoListo());

		barra.add(botonEscanear);
		barra.add(botonActualizarTodo);
		barra.add(etiquetaEstado);

		modeloActualizaciones = new ModeloActualizaciones();
		tablaActualizaciones = new JTable(modeloActualizaciones);
		tablaActualizaciones.setRowHeight(26);

		tablaActualizaciones.getColumnModel().getColumn(6).setCellRenderer(new RenderizadorBotonActualizar());
		tablaActualizaciones.getColumnModel().getColumn(6).setCellEditor(new EditorBotonActualizar(this));

		panelDerecho.add(barra, BorderLayout.NORTH);
		panelDerecho.add(new JScrollPane(tablaActualizaciones), BorderLayout.CENTER);

		JSplitPane split = new JSplitPane(JSplitPane.HORIZONTAL_SPLIT, panelIzquierdo, panelDerecho);
		split.setDividerLocation(250);
		split.setResizeWeight(0.0);

		add(split, BorderLayout.CENTER);

		botonEscanear.addActionListener(e -> escanearActualizacionesAsync());
		botonActualizarTodo.addActionListener(e -> actualizarTodoAsync());

		recargarApariencia();
		setVisible(true);
	}

	public void escanearActualizacionesAsync() {
		cancelarWorker();

		setEstado(MonitorDePID.idioma.actualizadorModsEstadoEscaneando());
		setBotonesActivos(false);

		worker = new SwingWorker<Void, Void>() {
			public List<ColaActualizacionesModpack.ActualizacionPendiente> encontradas = new ArrayList<>();

			@Override
			public Void doInBackground() throws Exception {
				encontradas = ColaActualizacionesModpack.crearCola(carpetaInstancia);
				return null;
			}

			@Override
			public void done() {
				try {
					get();
					cola = encontradas;
					modeloActualizaciones.establecerFilas(cola);

					if (cola.isEmpty()) {
						setEstado(MonitorDePID.idioma.actualizadorModsEstadoSinActualizaciones());
					} else {
						setEstado(MonitorDePID.idioma.actualizadorModsEstadoEncontradas(cola.size()));
					}
				} catch (Throwable t) {
					CrashDetectorLogger.logException(t);
					setEstado(MonitorDePID.idioma.actualizadorModsEstadoError());
					JOptionPane.showMessageDialog(ActualizadorModsGUI.this, t.getMessage(), MonitorDePID.idioma.error(),
							JOptionPane.ERROR_MESSAGE);
				} finally {
					setBotonesActivos(true);
				}
			}
		};

		worker.execute();
	}

	public void actualizarTodoAsync() {
		if (cola == null || cola.isEmpty()) {
			JOptionPane.showMessageDialog(this, MonitorDePID.idioma.actualizadorModsSinSeleccion(),
					MonitorDePID.idioma.informacion(), JOptionPane.INFORMATION_MESSAGE);
			return;
		}

		activarColaAsync(new ArrayList<ColaActualizacionesModpack.ActualizacionPendiente>(cola));
	}

	public void actualizarUnaAsync(int fila) {
		if (fila < 0 || fila >= cola.size()) {
			return;
		}

		List<ColaActualizacionesModpack.ActualizacionPendiente> una = new ArrayList<>();
		una.add(cola.get(fila));
		activarColaAsync(una);
	}

	public void activarColaAsync(final List<ColaActualizacionesModpack.ActualizacionPendiente> seleccion) {
		cancelarWorker();

		setEstado(MonitorDePID.idioma.actualizadorModsEstadoActualizando());
		setBotonesActivos(false);

		worker = new SwingWorker<Void, Void>() {
			private int aplicadas;

			@Override
			protected Void doInBackground() throws Exception {
				aplicadas = ColaActualizacionesModpack.activarCola(carpetaInstancia, seleccion);
				return null;
			}

			@Override
			protected void done() {
				try {
					get();
					setEstado(MonitorDePID.idioma.actualizadorModsEstadoActualizadas(aplicadas));
					escanearActualizacionesAsync();
				} catch (Throwable t) {
					CrashDetectorLogger.logException(t);
					setEstado(MonitorDePID.idioma.actualizadorModsEstadoError());
					JOptionPane.showMessageDialog(ActualizadorModsGUI.this, t.getMessage(), MonitorDePID.idioma.error(),
							JOptionPane.ERROR_MESSAGE);
					setBotonesActivos(true);
				}
			}
		};

		worker.execute();
	}

	public void cancelarWorker() {
		if (worker != null && !worker.isDone()) {
			worker.cancel(true);
		}
	}

	public void setEstado(String texto) {
		if (etiquetaEstado != null) {
			etiquetaEstado.setText(texto);
		}
	}

	public void setBotonesActivos(boolean activo) {
		if (botonEscanear != null) {
			botonEscanear.setEnabled(activo);
		}
		if (botonActualizarTodo != null) {
			botonActualizarTodo.setEnabled(activo && cola != null && !cola.isEmpty());
		}
		if (tablaActualizaciones != null) {
			tablaActualizaciones.setEnabled(activo);
		}
	}

	public static class ModeloActualizaciones extends AbstractTableModel {
		private final List<ColaActualizacionesModpack.ActualizacionPendiente> filas = new ArrayList<>();

		public void establecerFilas(List<ColaActualizacionesModpack.ActualizacionPendiente> nuevas) {
			filas.clear();
			if (nuevas != null) {
				filas.addAll(nuevas);
			}
			fireTableDataChanged();
		}

		public ColaActualizacionesModpack.ActualizacionPendiente obtener(int fila) {
			return filas.get(fila);
		}

		@Override
		public int getRowCount() {
			return filas.size();
		}

		@Override
		public int getColumnCount() {
			return 7;
		}

		@Override
		public String getColumnName(int col) {
			switch (col) {
			case 0:
				return MonitorDePID.idioma.actualizadorModsColumnaMod();
			case 1:
				return MonitorDePID.idioma.actualizadorModsColumnaActual();
			case 2:
				return MonitorDePID.idioma.actualizadorModsColumnaNueva();
			case 3:
				return MonitorDePID.idioma.actualizadorModsColumnaFuente();
			case 4:
				return MonitorDePID.idioma.actualizadorModsColumnaLoader();
			case 5:
				return MonitorDePID.idioma.actualizadorModsColumnaRuta();
			case 6:
				return MonitorDePID.idioma.actualizadorModsColumnaAccion();
			default:
				return "";
			}
		}

		@Override
		public Object getValueAt(int fila, int col) {
			ColaActualizacionesModpack.ActualizacionPendiente a = filas.get(fila);

			switch (col) {
			case 0:
				return a.nombreActual;
			case 1:
				return a.curseForgeFileIdActual > 0 ? String.valueOf(a.curseForgeFileIdActual)
						: valor(a.modrinthVersionIdActual);
			case 2:
				return a.nombreNuevo;
			case 3:
				return a.fuente;
			case 4:
				return a.loader;
			case 5:
				return a.rutaRelativa;
			case 6:
				return MonitorDePID.idioma.actualizadorModsBotonActualizarUno();
			default:
				return "";
			}
		}

		@Override
		public boolean isCellEditable(int row, int col) {
			return col == 6;
		}

		private String valor(String s) {
			return s == null ? "" : s;
		}
	}
}package com.asbestosstar.crashdetector.gui.tipos.antimanipulacion;

import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.LinkedHashSet;
import java.util.Set;
import java.util.function.Supplier;
import java.util.HashMap;
import java.util.Map;

import javax.swing.JDialog;
import javax.swing.JFileChooser;
import javax.swing.JOptionPane;
import javax.swing.JTable;
import javax.swing.table.DefaultTableModel;

import com.asbestosstar.crashdetector.MonitorDePID;
import com.asbestosstar.crashdetector.Statics;
import com.asbestosstar.crashdetector.config.json.Json;
import com.asbestosstar.crashdetector.config.json.Json.Nodo;
import com.asbestosstar.crashdetector.gui.CrashDetectorGUI;
import com.asbestosstar.crashdetector.gui.tipos.TipoGUI;

public abstract class AntiManipulacionGUI extends JDialog implements CrashDetectorGUI {

	public static final long serialVersionUID = 1L;

	public static final Map<String, Supplier<AntiManipulacionGUI>> GUIS = new HashMap<String, Supplier<AntiManipulacionGUI>>();

	public static final Path ARCHIVO = Statics.carpeta.resolve("antimanipulacion.json");

	public final Path baseDir = Paths.get(System.getProperty("user.dir")).toAbsolutePath();

	public final Set<String> rutasProtegidas = new LinkedHashSet<String>();

	public JTable tabla;
	public DefaultTableModel modelo;

	protected void inicializarModeloTabla() {
		modelo = new DefaultTableModel(new Object[] { MonitorDePID.idioma.rutaArchivo() }, 0) {
			private static final long serialVersionUID = 1L;

			@Override
			public boolean isCellEditable(int r, int c) {
				return false;
			}
		};

		tabla = new JTable(modelo);
		tabla.setRowHeight(24);
	}

	protected void seleccionar(boolean carpeta) {
		JFileChooser fc = new JFileChooser(baseDir.toFile());
		fc.setFileSelectionMode(carpeta ? JFileChooser.DIRECTORIES_ONLY : JFileChooser.FILES_ONLY);

		if (fc.showOpenDialog(this) != JFileChooser.APPROVE_OPTION)
			return;

		Path seleccionado = fc.getSelectedFile().toPath().toAbsolutePath();

		if (!seleccionado.startsWith(baseDir)) {
			JOptionPane.showMessageDialog(this, MonitorDePID.idioma.errorRutaFueraDirectorio(),
					MonitorDePID.idioma.error(), JOptionPane.ERROR_MESSAGE);
			return;
		}

		try {
			if (carpeta) {
				Files.walk(seleccionado).filter(Files::isRegularFile)
						.forEach(p -> rutasProtegidas.add(baseDir.relativize(p).toString()));
			} else {
				rutasProtegidas.add(baseDir.relativize(seleccionado).toString());
			}
		} catch (Exception e) {
			JOptionPane.showMessageDialog(this, e.getMessage());
		}

		recargarTabla();
	}

	protected void quitarSeleccionado() {
		int fila = tabla.getSelectedRow();
		if (fila < 0)
			return;

		Object val = modelo.getValueAt(fila, 0);
		if (val != null) {
			rutasProtegidas.remove(val.toString());
		}

		recargarTabla();
	}

	protected void recargarTabla() {
		modelo.setRowCount(0);
		for (String r : rutasProtegidas) {
			modelo.addRow(new Object[] { r });
		}
	}

	protected void cargarDatos() {
		rutasProtegidas.clear();

		if (!Files.exists(ARCHIVO))
			return;

		try {
			String json = new String(Files.readAllBytes(ARCHIVO), java.nio.charset.StandardCharsets.UTF_8);

			if (json.trim().isEmpty())
				return;

			Nodo raiz = Json.leer(json);
			if (!raiz.esArreglo())
				return;

			for (int i = 0; i < raiz.tamano(); i++) {
				Nodo n = raiz.en(i);
				if (n == null || !n.esObjeto())
					continue;

				Nodo r = n.obtener("ruta");
				if (r != null && !r.esObjeto() && !r.esArreglo()) {
					String v = r.comoCadena();
					if (v != null && !v.isEmpty()) {
						rutasProtegidas.add(v);
					}
				}
			}
		} catch (Exception ignored) {
		}
	}

	protected void guardarDatos() {
		try {
			Json.Nodo raiz = Json.leer("[]");

			for (String r : rutasProtegidas) {
				Json.Nodo obj = Json.crearObjeto();
				obj.obtener("ruta").poner(r);
				raiz.agregar(obj);
			}

			Files.write(ARCHIVO, raiz.aBytesUtf8());
		} catch (Exception e) {
			JOptionPane.showMessageDialog(this, e.getMessage(), MonitorDePID.idioma.error(), JOptionPane.ERROR_MESSAGE);
		}
	}

	@Override
	public TipoGUI tipo() {
		return TipoGUI.ANTI_MANIPULACION;
	}
}
